span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;44&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;45&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;46&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;47&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;48&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;49&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;50&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;// 输出&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;51&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; i &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; i &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt; size&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; i&lt;span class=&#34;token operator&#34;&gt;++&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;52&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;53&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        cout&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&amp;lt;&lt;/span&gt;endl&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;54&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; j &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; j &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt; size&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; j&lt;span class=&#34;token operator&#34;&gt;++&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;55&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;56&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;57&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            cout&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;setw&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&amp;lt;&lt;/span&gt;element&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;j&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;58&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;59&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;60&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;61&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;// 面板停留&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;62&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;system&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;pause&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;63&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;64&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;方阵乘法运算&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#方阵乘法运算&#34;&gt;#&lt;/a&gt; 方阵乘法运算&lt;/h3&gt;
&lt;h4 id=&#34;题目描述-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#题目描述-3&#34;&gt;#&lt;/a&gt; 题目描述&lt;/h4&gt;
&lt;p&gt;从键盘输入一个正整数 n（n 属于 [1,10]），表示进行乘法运算的两个整形方阵的阶。然后分别输入两个整形方阵 A 和 B，计算 A*B 后将结果输出到屏幕。&lt;/p&gt;
&lt;h4 id=&#34;输入输出格式-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输入输出格式-3&#34;&gt;#&lt;/a&gt; 输入输出格式&lt;/h4&gt;
&lt;h5 id=&#34;输入格式-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输入格式-3&#34;&gt;#&lt;/a&gt; 输入格式&lt;/h5&gt;
&lt;p&gt;从键盘输入一个正整数，然后再输入两个整形方阵。&lt;/p&gt;
&lt;h5 id=&#34;输出格式-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输出格式-3&#34;&gt;#&lt;/a&gt; 输出格式&lt;/h5&gt;
&lt;p&gt;在屏幕上输出两个整形方阵的乘积。&lt;/p&gt;
&lt;h4 id=&#34;输入输出样例-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输入输出样例-3&#34;&gt;#&lt;/a&gt; 输入输出样例&lt;/h4&gt;
&lt;h5 id=&#34;输入样例-1-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输入样例-1-3&#34;&gt;#&lt;/a&gt; 输入样例 #1&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;3
1 1 1
3 3 3
6 6 6
9 9 9
6 6 6
5 5 5
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;输出样例-1-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输出样例-1-3&#34;&gt;#&lt;/a&gt; 输出样例 #1&lt;/h5&gt;
&lt;p&gt;########20########20########20&lt;br /&gt;
########60########60########60&lt;br /&gt;
#######120#######120#######120&lt;/p&gt;
&lt;h4 id=&#34;样例说明-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#样例说明-2&#34;&gt;#&lt;/a&gt; 样例说明&lt;/h4&gt;
&lt;p&gt;首先输入正整数 3, 说明接下来要输入的方阵是 3*3 的。因为&lt;br /&gt;
 1 1 1     9 9 9     20 20 20&lt;br /&gt;
3 3 3  *  6 6 6  =  60 60 60&lt;br /&gt;
6 6 6    5 5 5     120 120 120&lt;br /&gt;
 所以在屏幕上打印：&lt;br /&gt;
########20########20########20&lt;br /&gt;
########60########60########60&lt;br /&gt;
#######120#######120#######120&lt;/p&gt;
&lt;p&gt;注：&amp;quot;#&amp;quot; 代表空格，每个输出的整数占 10 位，不足 10 位在整数的左边用空格补足。&lt;/p&gt;
&lt;h4 id=&#34;题解-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#题解-3&#34;&gt;#&lt;/a&gt; 题解&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;代码：上杉九月&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h5 id=&#34;思路-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#思路-3&#34;&gt;#&lt;/a&gt; 思路&lt;/h5&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;element[]&lt;/code&gt;  为存储第一个矩阵， &lt;code&gt;element_02[]&lt;/code&gt;  为存储第二个矩阵， &lt;code&gt;element_03[]&lt;/code&gt;  为输出结果矩阵&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9iYWlrZS5iYWlkdS5jb20vaXRlbS8lRTclOUYlQTklRTklOTglQjUlRTQlQjklOTglRTYlQjMlOTUvNTQ0NjAyOT9mcj1hbGFkZGlu&#34;&gt;矩阵乘法_百度百科 (baidu.com)&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;只要是看懂了矩阵的乘法运算规律，通过一一对应，本题便能做出来。&lt;/li&gt;
&lt;/ul&gt;
&lt;h5 id=&#34;ac代码-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ac代码-3&#34;&gt;#&lt;/a&gt; AC 代码&lt;/h5&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;#include &amp;lt;iostream&amp;gt;
#include &amp;lt;cstdio&amp;gt;
#include &amp;lt;iomanip&amp;gt;
using namespace std;
int x, y;
int main()
&amp;#123;

    // 定义动态二维数组
    int **element = NULL;
    int **element_02 = NULL;
    int **element_03 = NULL;
    int size;
    cin&amp;gt;&amp;gt;size;

    element = new int *[size];
    for(int i = 0; i &amp;lt; size; i++)
    &amp;#123;
        element[i] = new int [size];
    &amp;#125;

    element_02 = new int *[size];
    for(int i = 0; i &amp;lt; size; i++)
    &amp;#123;
        element_02[i] = new int [size];
    &amp;#125;

    element_03 = new int *[size];
    for(int i = 0; i &amp;lt; size; i++)
    &amp;#123;
        element_03[i] = new int [size];
    &amp;#125;

    // 输入数据
    for(int i = 0; i &amp;lt; size; i++)
    &amp;#123;
        for(int j = 0; j &amp;lt; size; j++)
        &amp;#123;
            cin&amp;gt;&amp;gt;element[i][j];
        &amp;#125;
    &amp;#125;

    for(int i = 0; i &amp;lt; size; i++)
    &amp;#123;
        for(int j = 0; j &amp;lt; size; j++)
        &amp;#123;
            cin&amp;gt;&amp;gt;element_02[i][j];
        &amp;#125;
    &amp;#125;

    // 核心代码

    for(int i = 0; i &amp;lt; size; i++)
    &amp;#123;
        for(int j = 0; j &amp;lt; size; j++)
        &amp;#123;
            element_03[i][j] = 0;
        &amp;#125;
    &amp;#125;

    for(int i = 0; i &amp;lt; size; i++)
    &amp;#123;
        for(int j = 0; j &amp;lt; size; j++)
        &amp;#123;
            int num = size;
            int y = 0;
            while(num &amp;gt; 0)
            &amp;#123;
                element_03[i][j] += element[i][y] * element_02[y][j];
                y++;
                num--;
            &amp;#125;   
        &amp;#125;
    &amp;#125;



    // 结果输出
    for(int i = 0; i &amp;lt; size; i++)
    &amp;#123;
        for(int j = 0; j &amp;lt; size; j++)
        &amp;#123;
            cout&amp;lt;&amp;lt;setw(10)&amp;lt;&amp;lt;element_03[i][j];
        &amp;#125;
        cout&amp;lt;&amp;lt;endl;
    &amp;#125;

    // VSCode
    system(&amp;quot;pause&amp;quot;);
    return 0;


&amp;#125;
/*
3
1 1 1 9 9 9
3 3 3 6 6 6
6 6 6 5 5 5
*/
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;n阶魔方阵&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#n阶魔方阵&#34;&gt;#&lt;/a&gt; N 阶魔方阵&lt;/h3&gt;
&lt;h4 id=&#34;题目描述-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#题目描述-4&#34;&gt;#&lt;/a&gt; 题目描述&lt;/h4&gt;
&lt;p&gt;魔方阵指一个 A 是 NxN 矩阵（在本题中 N 仅为奇数，且 N&amp;gt;1），以自然数 1，2， 。。。 N2 为元素进行填充，每个位置上分别放置一个元素，使每行、每列以及主、副对角线上的元素之和都相等。&lt;br /&gt;
如 3x3 魔方阵，图在每行、每列、主对角线、副对角线上元素之和均为 15：&lt;br /&gt;
8 1 6&lt;br /&gt;
3 5 7&lt;br /&gt;
4 9 2&lt;br /&gt;
 奇数阶魔方阵的生成算法如下，初始矩阵 A 为空，从 1 开始依据下面的规则依次放置各个自然数（注意在下面的叙述中各元素行、列下标均以 1-N 计数）：&lt;br /&gt;
\1. 将 1 放在第一行正中的位置，即 A [1, (j+1)/2]；&lt;br /&gt;
\2. 设最后放置的元素是 A [i, j]，则将下一个元素放在最后一个插入位置的右上方，即 A [i-1, j+1]。但如果该位置已超出方阵的上边界（即如果 i&amp;lt;0），则新位置取该列的最下一个位置，即 A [N, j+1]；如果该位置已超出方阵的右边界，取新位置取该行的最左一个位置，即 A [i-1, 1]。&lt;br /&gt;
\3. 若最近一个插入元素为 N 的整倍数，则新位置取最后插入元素下面的位置，即 A [i+1, j]。&lt;br /&gt;
输入一个奇数 N，打印对应的 N 阶魔方阵。&lt;/p&gt;
&lt;h4 id=&#34;输入输出格式-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输入输出格式-4&#34;&gt;#&lt;/a&gt; 输入输出格式&lt;/h4&gt;
&lt;h5 id=&#34;输入格式-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输入格式-4&#34;&gt;#&lt;/a&gt; 输入格式&lt;/h5&gt;
&lt;p&gt;控制台输入一奇数 N。&lt;/p&gt;
&lt;h5 id=&#34;输出格式-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输出格式-4&#34;&gt;#&lt;/a&gt; 输出格式&lt;/h5&gt;
&lt;p&gt;输出一个 N*N 的魔方阵，其中每个数字占 4 位字符的宽度，向右对齐。&lt;/p&gt;
&lt;h4 id=&#34;输入输出样例-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输入输出样例-4&#34;&gt;#&lt;/a&gt; 输入输出样例&lt;/h4&gt;
&lt;h5 id=&#34;输入样例-1-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输入样例-1-4&#34;&gt;#&lt;/a&gt; 输入样例 #1&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;5
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;输出样例-1-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输出样例-1-4&#34;&gt;#&lt;/a&gt; 输出样例 #1&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;  17  24   1   8  15
  23   5   7  14  16
   4   6  13  20  22
  10  12  19  21   3
  11  18  25   2   9
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;样例说明-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#样例说明-3&#34;&gt;#&lt;/a&gt; 样例说明&lt;/h4&gt;
&lt;p&gt;输入奇数 5，输出 5 阶魔方阵。&lt;/p&gt;
&lt;h4 id=&#34;题解-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#题解-4&#34;&gt;#&lt;/a&gt; 题解&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;代码：上杉九月&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h5 id=&#34;思路-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#思路-4&#34;&gt;#&lt;/a&gt; 思路&lt;/h5&gt;
&lt;ul&gt;
&lt;li&gt;本题主要是考察限定规则，题目中每一次新的位置都是在原来位置的右上方，此时你需要考虑两种情况：一是超出数组的边界，一是右上角已经存在数据。&lt;/li&gt;
&lt;li&gt;本题代码使用了 &lt;code&gt;maps&lt;/code&gt;  数组来标记数据的填充，在每一次填数操作后都使得该位置的 &lt;code&gt;maps&lt;/code&gt;  数组为 1。&lt;/li&gt;
&lt;li&gt;判断情况有以下几种。
&lt;ul&gt;
&lt;li&gt;超右边界但是不超上边界&lt;/li&gt;
&lt;li&gt;超上边界但是不超右边界&lt;/li&gt;
&lt;li&gt;既超上边界也超右边界&lt;/li&gt;
&lt;li&gt;既不超上边界也不超右边界&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h5 id=&#34;ac代码-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ac代码-4&#34;&gt;#&lt;/a&gt; AC 代码&lt;/h5&gt;
